import React, { useEffect } from "react";
import { MapContainer, TileLayer, Marker, useMap } from "react-leaflet";
import L from "leaflet";
import "leaflet-routing-machine";

function Routing({ origin, destination }) {

  const map = useMap();

  useEffect(() => {

    if (!origin || !destination) return;

    const control = L.Routing.control({

      waypoints: [
        L.latLng(origin.lat, origin.lon),
        L.latLng(destination.lat, destination.lon)
      ],

      lineOptions: {
        styles: [{ color: "#ff4f81", weight: 6 }]
      },

      addWaypoints: false,
      routeWhileDragging: false,
      draggableWaypoints: false

    }).addTo(map);

    return () => map.removeControl(control);

  }, [origin, destination]);

  return null;

}

const pinkIcon = new L.Icon({
  iconUrl: "https://cdn-icons-png.flaticon.com/512/684/684908.png",
  iconSize: [35, 35]
});

function GoogleMapView({ originCoords, destinationCoords }) {

  if (!originCoords) {
    return <p>Getting your location...</p>;
  }

  return (

    <MapContainer
      center={[originCoords.lat, originCoords.lon]}
      zoom={14}
      style={{ height: "400px", width: "100%" }}
    >

      {/* Google-like map tiles */}

      <TileLayer
        url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
      />

      {/* Current Location */}

      <Marker
        position={[originCoords.lat, originCoords.lon]}
      />

      {/* Destination */}

      {destinationCoords && (

        <Marker
          position={[destinationCoords.lat, destinationCoords.lon]}
          icon={pinkIcon}
        />

      )}

      {/* Pink navigation */}

      {destinationCoords && (

        <Routing
          origin={originCoords}
          destination={destinationCoords}
        />

      )}

    </MapContainer>

  );

}

export default GoogleMapView;
